using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 0 || n == 0) return 0;

    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}};

    // Priority queue: (total_cost, i, j, time_mod)
    priority_queue<tuple<long long, int, int, int>, 
                   vector<tuple<long long, int, int, int>>, 
                   greater<tuple<long long, int, int, int>>> pq;

    // Cost matrix: cost[i][j][time_mod] represents the minimal cost to reach (i,j) with time_mod (0 or 1)
    vector<vector<vector<long long>>> cost(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));

    // Initial state: (0,0) with time_mod 1 (since first step is at time 1)
    cost[0][0][1] = (0 + 1) * (0 + 1); // entry cost for (0,0)
    pq.push({cost[0][0][1], 0, 0, 1});

    while (!pq.empty()) {
        auto [current_cost, i, j, time_mod] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (current_cost > cost[i][j][time_mod]) {
            continue;
        }

        if (time_mod == 1) {
            // Odd second: move right or down
            for (auto [di, dj] : dirs) {
                int ni = i + di;
                int nj = j + dj;
                if (ni < m && nj < n) {
                    long long new_cost = current_cost + (ni + 1) * (nj + 1);
                    if (new_cost < cost[ni][nj][0]) {
                        cost[ni][nj][0] = new_cost;
                        pq.push({new_cost, ni, nj, 0});
                    }
                }
            }
        } else {
            // Even second: wait
            long long new_cost = current_cost + waitCost[i][j];
            if (new_cost < cost[i][j][1]) {
                cost[i][j][1] = new_cost;
                pq.push({new_cost, i, j, 1});
            }
        }
    }

    return -1; // unreachable
}

