    // Directions: right (0, 1), down (1, 0)
    const dirs = [[0, 1], [1, 0]];

    // Priority queue: [total_cost, i, j, time_mod]
    const pq = new MinPriorityQueue({
        priority: ([cost]) => cost
    });

    // Cost matrix: cost[i][j][time_mod] represents the minimal cost to reach (i,j) with time_mod (0 or 1)
    const cost = Array.from({ length: m }, () => 
        Array.from({ length: n }, () => 
            [Infinity, Infinity]
        )
    );

    // Initial state: (0,0) with time_mod 1 (since first step is at time 1)
    cost[0][0][1] = (0 + 1) * (0 + 1); // entry cost for (0,0)
    pq.enqueue([cost[0][0][1], 0, 0, 1]);

    while (!pq.isEmpty()) {
        const { element: [current_cost, i, j, time_mod] } = pq.dequeue();

        if (i === m - 1 && j === n - 1) {
            return current_cost;
        }

        if (current_cost > cost[i][j][time_mod]) {
            continue;
        }

        if (time_mod === 1) {
            // Odd second: move right or down
            for (const [di, dj] of dirs) {
                const ni = i + di;
                const nj = j + dj;
                if (ni < m && nj < n) {
                    const new_cost = current_cost + (ni + 1) * (nj + 1);
                    if (new_cost < cost[ni][nj][0]) {
                        cost[ni][nj][0] = new_cost;
                        pq.enqueue([new_cost, ni, nj, 0]);
                    }
                }
            }
        } else {
            // Even second: wait
            const new_cost = current_cost + waitCost[i][j];
            if (new_cost < cost[i][j][1]) {
                cost[i][j][1] = new_cost;
                pq.enqueue([new_cost, i, j, 1]);
            }
        }
    }

    return -1; // unreachable
}

